pipeline.evaluate:
(async () => {
  const username = '${{ args.username }}';
  let attempts = 0;

  while (attempts < 20) {
    const unfollowBtn = document.querySelector('[data-testid$="-unfollow"]');
    if (unfollowBtn) return [{ status: 'success', message: 'Already following @' + username }];

    const followBtn = document.querySelector('[data-testid$="-follow"]');
    if (followBtn) {
      followBtn.click();
      await new Promise(r => setTimeout(r, 1500));
      const verify = document.querySelector('[data-testid$="-unfollow"]');
      if (verify) return [{ status: 'success', message: 'Successfully followed @' + username }];
      return [{ status: 'failed', message: 'Follow action initiated but UI did not update' }];
    }

    await new Promise(r => setTimeout(r, 500));
    attempts++;
  }

  return [{ status: 'failed', message: 'Could not find Follow button' }];
})()
